@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Track Shipment</PageTitle>

<div class="container mt-4">
    <h2>Track Your Shipment</h2>

    <div class="row mt-3">
        <div class="col-md-6">
            <div class="input-group">
                <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-20260525-123456)"
                       @bind="trackingNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                    @if (isLoading)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Track
                </button>
            </div>
        </div>
    </div>

    @if (errorMessage is not null)
    {
        <div class="alert alert-warning mt-3">@errorMessage</div>
    }

    @if (shipment is not null)
    {
        <div class="card mt-4">
            <div class="card-header">
                <strong>@shipment.TrackingNumber</strong>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6">
                        <dl>
                            <dt>Status</dt>
                            <dd><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></dd>
                            <dt>Description</dt>
                            <dd>@shipment.Description</dd>
                            <dt>Origin</dt>
                            <dd>@shipment.Origin</dd>
                            <dt>Destination</dt>
                            <dd>@shipment.Destination</dd>
                        </dl>
                    </div>
                    <div class="col-md-6">
                        <dl>
                            <dt>Shipped On</dt>
                            <dd>@shipment.CreatedAt.ToString("MMM dd, yyyy")</dd>
                            <dt>Estimated Delivery</dt>
                            <dd>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "Pending")</dd>
                            @if (shipment.DeliveredAt.HasValue)
                            {
                                <dt>Delivered On</dt>
                                <dd>@shipment.DeliveredAt.Value.ToString("MMM dd, yyyy HH:mm")</dd>
                            }
                        </dl>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private string trackingNumber = string.Empty;
    private Shipment? shipment;
    private string? errorMessage;
    private bool isLoading;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isLoading = true;
        errorMessage = null;
        shipment = null;

        try
        {
            shipment = await ShipmentService.GetByTrackingNumberAsync(trackingNumber.Trim());
            if (shipment is null)
                errorMessage = "No shipment found with that tracking number.";
        }
        catch
        {
            errorMessage = "An error occurred while looking up the shipment.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-info text-dark",
        ShipmentStatus.OutForDelivery => "bg-primary",
        ShipmentStatus.Exception => "bg-danger",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-warning text-dark"
    };
}

@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Dispatcher Dashboard</PageTitle>

<div class="container-fluid mt-4">
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h2>Shipments</h2>
        <button class="btn btn-success" @onclick="ShowCreateForm">+ New Shipment</button>
    </div>

    <div class="row mb-3">
        <div class="col-md-4">
            <input type="text" class="form-control" placeholder="Filter by destination..."
                   @bind="filterText" @bind:event="oninput" />
        </div>
        <div class="col-md-3">
            <select class="form-select" @bind="statusFilter">
                <option value="">All Statuses</option>
                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                {
                    <option value="@status">@status</option>
                }
            </select>
        </div>
    </div>

    @if (isLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border" role="status"></div>
            <p class="mt-2">Loading shipments...</p>
        </div>
    }
    else if (errorMessage is not null)
    {
        <div class="alert alert-danger">@errorMessage</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Tracking #</th>
                        <th>Description</th>
                        <th>Destination</th>
                        <th>Status</th>
                        <th>Est. Delivery</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var shipment in FilteredShipments)
                    {
                        <tr>
                            <td><code>@shipment.TrackingNumber</code></td>
                            <td>@shipment.Description</td>
                            <td>@shipment.Destination</td>
                            <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                            <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                            <td>
                                <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                        value="@shipment.Status"
                                        @onchange="(e) => UpdateStatus(shipment, e)">
                                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                    {
                                        <option value="@status" selected="@(status == shipment.Status)">@status</option>
                                    }
                                </select>
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        @if (!FilteredShipments.Any())
        {
            <p class="text-muted text-center">No shipments match your filters.</p>
        }
    }

    @if (showCreate)
    {
        <div class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.5)">
            <div class="modal-dialog">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Create New Shipment</h5>
                        <button type="button" class="btn-close" @onclick="() => showCreate = false"></button>
                    </div>
                    <div class="modal-body">
                        <div class="mb-3">
                            <label class="form-label">Description</label>
                            <input type="text" class="form-control" @bind="newShipment.Description" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Origin</label>
                            <input type="text" class="form-control" @bind="newShipment.Origin" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Destination</label>
                            <input type="text" class="form-control" @bind="newShipment.Destination" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Customer Email</label>
                            <input type="email" class="form-control" @bind="newShipment.CustomerEmail" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Estimated Delivery</label>
                            <input type="date" class="form-control" @bind="estimatedDeliveryDate" />
                        </div>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="() => showCreate = false">Cancel</button>
                        <button class="btn btn-primary" @onclick="CreateShipment" disabled="@isSaving">
                            @if (isSaving)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Create
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Shipment> shipments = [];
    private bool isLoading = true;
    private bool showCreate;
    private bool isSaving;
    private string? errorMessage;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;
    private Shipment newShipment = new();
    private DateTime? estimatedDeliveryDate;

    private IEnumerable<Shipment> FilteredShipments => shipments.Where(s =>
        (string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
        (string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter));

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        catch
        {
            errorMessage = "Failed to load shipments.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ShowCreateForm()
    {
        newShipment = new Shipment();
        estimatedDeliveryDate = DateTime.UtcNow.AddDays(5);
        showCreate = true;
    }

    private async Task CreateShipment()
    {
        isSaving = true;
        try
        {
            newShipment.EstimatedDelivery = estimatedDeliveryDate;
            await ShipmentService.CreateShipmentAsync(newShipment);
            showCreate = false;
            await LoadShipments();
        }
        catch
        {
            errorMessage = "Failed to create shipment.";
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            try
            {
                var updated = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
                shipment.Status = updated.Status;
                shipment.DeliveredAt = updated.DeliveredAt;
            }
            catch
            {
                errorMessage = "Failed to update status.";
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-info text-dark",
        ShipmentStatus.OutForDelivery => "bg-primary",
        ShipmentStatus.Exception => "bg-danger",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-warning text-dark"
    };
}

