                            <td>@shipment.Description</td>
                            <td>@shipment.Destination</td>
                            <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                            <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                            <td>
                                <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                        value="@shipment.Status"
                                        @onchange="(e) => UpdateStatus(shipment, e)">
                                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                    {
                                        <option value="@status" selected="@(status == shipment.Status)">@status</option>
                                    }
                                </select>
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        @if (!FilteredShipments.Any())
        {
            <p class="text-muted text-center">No shipments match your filters.</p>
        }
    }

    @if (showCreate)
    {
        <div class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.5)">
            <div class="modal-dialog">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Create New Shipment</h5>
                        <button type="button" class="btn-close" @onclick="() => showCreate = false"></button>
                    </div>
                    <div class="modal-body">
                        <div class="mb-3">
                            <label class="form-label">Description</label>
                            <input type="text" class="form-control" @bind="newShipment.Description" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Origin</label>
                            <input type="text" class="form-control" @bind="newShipment.Origin" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Destination</label>
                            <input type="text" class="form-control" @bind="newShipment.Destination" />
                        </div>
                        <div class="mb-3">
