@code {
    private List<Shipment> shipments = [];
    private bool isLoading = true;
    private bool showCreate;
    private bool isSaving;
    private string? errorMessage;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;
    private Shipment newShipment = new();
    private DateTime? estimatedDeliveryDate;

    private IEnumerable<Shipment> FilteredShipments => shipments.Where(s =>
        (string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
        (string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter));

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        catch
        {
            errorMessage = "Failed to load shipments.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ShowCreateForm()
    {
        newShipment = new Shipment();
        estimatedDeliveryDate = DateTime.UtcNow.AddDays(5);
        showCreate = true;
    }

    private async Task CreateShipment()
    {
        isSaving = true;
        try
        {
            newShipment.EstimatedDelivery = estimatedDeliveryDate;
            await ShipmentService.CreateShipmentAsync(newShipment);
            showCreate = false;
            await LoadShipments();
        }
        catch
        {
            errorMessage = "Failed to create shipment.";
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            try
            {
                var updated = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
                shipment.Status = updated.Status;
                shipment.DeliveredAt = updated.DeliveredAt;
            }
            catch
            {
                errorMessage = "Failed to update status.";
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-info text-dark",
        ShipmentStatus.OutForDelivery => "bg-primary",
        ShipmentStatus.Exception => "bg-danger",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-warning text-dark"
    };
}

